import { createClient } from '@/lib/supabase/server'
import { notFound, redirect } from 'next/navigation'
import Link from 'next/link'
import { ChevronLeft, QrCode } from 'lucide-react'
import { LiveAttendance, SpotData } from '@/features/instructor/components/LiveAttendance'
import { AttendanceQRModal } from '@/features/instructor/components/AttendanceQRModal'

function formatSessionDate(isoString: string) {
  const hasTimezone = isoString.includes('Z') || /[-+]\d{2}:?\d{2}$/.test(isoString)
  const date = new Date(hasTimezone ? isoString : `${isoString}-05:00`)
  return new Intl.DateTimeFormat('es-PE', { 
    weekday: 'long', 
    day: 'numeric', 
    month: 'long',
    timeZone: 'America/Lima'
  }).format(date)
}

function formatSessionTime(isoString: string) {
  const hasTimezone = isoString.includes('Z') || /[-+]\d{2}:?\d{2}$/.test(isoString)
  const date = new Date(hasTimezone ? isoString : `${isoString}-05:00`)
  return new Intl.DateTimeFormat('es-PE', { 
    hour: '2-digit', 
    minute: '2-digit', 
    hour12: true,
    timeZone: 'America/Lima'
  }).format(date)
}

export default async function AttendancePage({ params }: { params: Promise<{ id: string }> }) {
  const resolvedParams = await params
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()

  if (!user) {
    redirect('/login')
  }

  // Fetch session and spots
  const { data: session, error } = await supabase
    .from('sessions')
    .select(`
      *,
      session_spots ( 
        spot_number, 
        status,
        reservation_spots (
          reservations (
            client_name,
            estado_pago,
            total_amount
          )
        )
      )
    `)
    .eq('id', resolvedParams.id)
    .eq('instructor_id', user.id)
    .single()

  if (error || !session) {
    notFound()
  }

  const spots = (session.session_spots || []) as SpotData[]
  const countPresent = spots.filter(s => s.status === 'present').length

  const dateStr = formatSessionDate(`${session.session_date}T${session.start_time}`)
  const timeStr = formatSessionTime(`${session.session_date}T${session.start_time}`)

  return (
    <div className="min-h-screen bg-background relative pb-24">
      {/* Top Gradient Header */}
      <div className="bg-gradient-to-r from-pink-500 to-purple-600 py-8 md:py-10 text-white relative">
        <div className="max-w-3xl mx-auto px-4 w-full">
          <Link href="/panel" className="inline-flex items-center gap-1 text-white/90 hover:text-white mb-4 text-sm font-medium transition-colors">
            <ChevronLeft className="w-4 h-4" />
            Volver al Panel
          </Link>
          
          <div className="flex justify-between items-center">
            <div>
              <h1 className="text-2xl font-bold">Asistencia en Vivo</h1>
              <p className="text-white/80 text-sm mt-1 capitalize">{dateStr} - {timeStr}</p>
            </div>
            <div className="flex flex-col items-center shrink-0">
              <span className="text-3xl font-bold">{countPresent}</span>
              <span className="text-xs text-white/80 uppercase tracking-wider font-medium">Presentes</span>
            </div>
          </div>

          <div className="mt-6 md:mt-8">
            <AttendanceQRModal />
          </div>
        </div>
      </div>

      <main className="max-w-3xl mx-auto px-4 mt-6">
        <LiveAttendance 
          sessionId={session.id}
          capacity={session.capacity}
          spots={spots}
        />
      </main>
    </div>
  )
}

import { createClient } from '@/lib/supabase/server'
import { redirect } from 'next/navigation'
import Link from 'next/link'
import { Clock, User as UserIcon } from 'lucide-react'
import { getLimaDateString } from '@/lib/utils'

function formatSessionDate(isoString: string) {
  const hasTimezone = isoString.includes('Z') || /[-+]\d{2}:?\d{2}$/.test(isoString)
  const date = new Date(hasTimezone ? isoString : `${isoString}-05:00`)
  return new Intl.DateTimeFormat('es-PE', { 
    weekday: 'long', 
    day: 'numeric', 
    month: 'long',
    timeZone: 'America/Lima'
  }).format(date)
}

function formatSessionTime(isoString: string) {
  const hasTimezone = isoString.includes('Z') || /[-+]\d{2}:?\d{2}$/.test(isoString)
  const date = new Date(hasTimezone ? isoString : `${isoString}-05:00`)
  return new Intl.DateTimeFormat('es-PE', { 
    hour: '2-digit', 
    minute: '2-digit', 
    hour12: true,
    timeZone: 'America/Lima'
  }).format(date)
}

function getOccupationTextColor(percentage: number) {
  if (percentage < 50) return 'text-[#00E676]'
  if (percentage < 90) return 'text-orange-500'
  return 'text-pink-500'
}

function getOccupationBgColor(percentage: number) {
  if (percentage < 50) return 'bg-[#00E676]'
  if (percentage < 90) return 'bg-orange-500'
  return 'bg-pink-500'
}

export default async function AsistenciaIndexPage() {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()

  if (!user) {
    redirect('/login')
  }

  // Fetch all upcoming sessions for this instructor
  const { data: sessions, error } = await supabase
    .from('sessions')
    .select(`
      *,
      session_spots ( status )
    `)
    .eq('instructor_id', user.id)
    .in('status', ['published', 'draft'])
    .order('session_date', { ascending: true })
    .order('start_time', { ascending: true })
    .gte('session_date', getLimaDateString())

  if (error) {
    console.error('Error fetching sessions:', error)
  }

  const upcomingSessions = (sessions || []) as any[]

  const getOccupation = (session: any) => {
    const reservedSpots = session.session_spots
      ? session.session_spots.filter((s: any) => s.status !== 'available').length
      : 0
    return {
      reserved: reservedSpots,
      capacity: session.capacity,
      percentage: (reservedSpots / session.capacity) * 100
    }
  }

  return (
    <div className="min-h-screen bg-background relative pb-24">
      {/* Top Gradient Header */}
      <div className="bg-gradient-to-r from-pink-500 to-purple-600 pt-8 pb-8 px-5 text-white">
        <div className="max-w-3xl mx-auto w-full">
          <h1 className="text-2xl font-bold">Monitoreo en Vivo</h1>
          <p className="text-white/80 text-sm mt-1">Selecciona una clase para visualizar</p>
        </div>
      </div>

      <main className="max-w-3xl mx-auto px-4 mt-6">
        {upcomingSessions.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {upcomingSessions.map((session, index) => {
              const isNext = index === 0
              return (
                <div key={session.id} className="bg-container rounded-3xl p-5 border border-foreground/5 shadow-xl space-y-5 flex flex-col justify-between">
                  <div className="space-y-5">
                    <div className={`flex items-center gap-2 text-sm font-semibold uppercase tracking-wider mb-2 ${isNext ? 'text-pink-500' : 'text-foreground/60'}`}>
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"></path>
                      </svg>
                      {isNext ? 'Próxima Clase' : 'Clase Programada'}
                    </div>
                    
                    <h2 className="text-2xl font-bold text-foreground capitalize">
                      {formatSessionDate(`${session.session_date}T${session.start_time}`)}
                    </h2>

                    <div className="space-y-4 pt-2">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 rounded-full bg-pink-500/10 flex items-center justify-center shrink-0">
                          <Clock className="w-5 h-5 text-pink-500" />
                        </div>
                        <div>
                          <p className="text-xs text-foreground/70">Hora</p>
                          <p className="text-sm font-medium text-foreground">{formatSessionTime(`${session.session_date}T${session.start_time}`)}</p>
                        </div>
                      </div>

                      {session.special_guest && (
                        <div className="flex items-center gap-4">
                          <div className="w-10 h-10 rounded-full bg-purple-500/10 flex items-center justify-center shrink-0">
                            <UserIcon className="w-5 h-5 text-purple-500" />
                          </div>
                          <div>
                            <p className="text-xs text-foreground/70">Invitada Especial</p>
                            <p className="text-sm font-medium text-foreground">{session.special_guest}</p>
                          </div>
                        </div>
                      )}
                    </div>

                    <div className="pt-2">
                      <div className="flex items-center justify-between mb-2">
                        <span className="text-sm text-foreground/70">Ocupación</span>
                        <span className={`text-sm font-bold ${getOccupationTextColor(getOccupation(session).percentage)}`}>
                          {getOccupation(session).reserved}/{getOccupation(session).capacity} Cupos
                        </span>
                      </div>
                      <div className="w-full h-2 bg-foreground/10 rounded-full overflow-hidden">
                        <div 
                          className={`h-full rounded-full transition-all ${getOccupationBgColor(getOccupation(session).percentage)}`}
                          style={{ width: `${getOccupation(session).percentage}%` }}
                        />
                      </div>
                    </div>
                  </div>

                  <div className="pt-4">
                    <Link href={`/panel/asistencia/${session.id}`} className="block w-full">
                      <button className="w-full bg-gradient-to-r from-pink-500 to-purple-600 text-white font-semibold rounded-xl py-3.5 transition-transform hover:scale-[1.02] active:scale-95 shadow-lg shadow-pink-500/25">
                        Ver Asistencia en Vivo
                      </button>
                    </Link>
                  </div>
                </div>
              )
            })}
          </div>
        ) : (
          <div className="bg-container rounded-3xl p-8 border border-foreground/5 shadow-xl text-center space-y-4">
            <h2 className="text-xl font-bold text-foreground">No hay clases activas</h2>
            <p className="text-foreground/70 text-sm">Actualmente no tienes clases programadas para monitorear.</p>
          </div>
        )}
      </main>
    </div>
  )
}

import { ClassCard } from '@/features/classes/components/ClassCard'
import { InstructorProfile } from '@/features/classes/components/InstructorProfile'
import { createClient } from '@/lib/supabase/server'
import { ClassFilters } from '@/features/classes/components/ClassFilters'
import { getCurrentLimaTime, getLimaYesterdayDateString } from '@/lib/utils'

function formatSessionDate(isoString: string) {
  const hasTimezone = isoString.includes('Z') || /[-+]\d{2}:?\d{2}$/.test(isoString)
  const date = new Date(hasTimezone ? isoString : `${isoString}-05:00`)
  return new Intl.DateTimeFormat('es-PE', { 
    weekday: 'long', 
    day: 'numeric', 
    month: 'short',
    timeZone: 'America/Lima'
  }).format(date)
}

function formatSessionTime(isoString: string) {
  const hasTimezone = isoString.includes('Z') || /[-+]\d{2}:?\d{2}$/.test(isoString)
  const date = new Date(hasTimezone ? isoString : `${isoString}-05:00`)
  return new Intl.DateTimeFormat('es-PE', { 
    hour: '2-digit', 
    minute: '2-digit', 
    hour12: true,
    timeZone: 'America/Lima'
  }).format(date)
}

type SearchParams = Promise<{ [key: string]: string | string[] | undefined }>

export default async function ClassesPage(props: { searchParams: SearchParams }) {
  const searchParams = await props.searchParams
  const supabase = await createClient()

  // Fetch instructors for filter
  const { data: instructorsData } = await supabase.from('instructors').select('id, full_name')
  const instructorsList = ((instructorsData as any[]) || []).map((i: any) => ({ id: i.id, name: i.full_name }))

  // Calculate local date of yesterday to make sure we don't miss late sessions crossing midnight or timezone offsets
  const yesterdayString = getLimaYesterdayDateString()

  // Base query for sessions
  let query = supabase
    .from('sessions')
    .select(`
      id,
      session_date,
      start_time,
      theme,
      class_type,
      capacity,
      price,
      instructor_id,
      session_spots ( id, status ),
      instructor:instructors (
        full_name,
        whatsapp_phone
      )
    `)
    .gte('session_date', yesterdayString)

  if (searchParams?.instructor && typeof searchParams.instructor === 'string') {
    query = query.eq('instructor_id', searchParams.instructor)
  }

  if (searchParams?.date && typeof searchParams.date === 'string') {
    query = query.eq('session_date', searchParams.date)
  }

  const { data: sessionsData, error } = await query.order('session_date', { ascending: true }).order('start_time', { ascending: true })

  const limaNow = getCurrentLimaTime()
  const mappedSessions = ((sessionsData as any[]) || [])
    .filter((session: any) => {
      // Parse local class date and start time manually to ensure it uses the local timezone (local server timezone representation)
      const [year, month, day] = session.session_date.split('-').map(Number)
      const [hour, minute] = session.start_time.split(':').map(Number)
      const sessionDateTime = new Date(year, month - 1, day, hour, minute)
      
      // A class expires exactly 1 hour after its start time
      const expirationTime = sessionDateTime.getTime() + 1 * 60 * 60 * 1000
      return limaNow.getTime() <= expirationTime
    })
    .map((session: any) => {
      const instructorName = session.instructor
        ? (Array.isArray(session.instructor) ? session.instructor[0]?.full_name : session.instructor.full_name)
        : 'Instructor'

      const availableSpots = session.session_spots
        ? session.session_spots.filter((s: any) => s.status === 'available').length
        : session.capacity

      return {
        id: session.id,
        date: formatSessionDate(`${session.session_date}T${session.start_time}`),
        time: formatSessionTime(`${session.session_date}T${session.start_time}`),
        instructorName,
        theme: session.theme,
        classType: session.class_type,
        totalSpots: session.capacity,
        availableSpots,
        price: session.price || 25
      }
    })

  // Destacar al instructor de la clase más próxima
  let featuredInstructor = null
  if (sessionsData && sessionsData.length > 0) {
    const firstSession = (sessionsData as any[])[0]
    const instructorObj = firstSession.instructor
      ? (Array.isArray(firstSession.instructor) ? firstSession.instructor[0] : firstSession.instructor)
      : null

    if (instructorObj && instructorObj.full_name) {
      const mockYears = (instructorObj.full_name?.length % 5) + 5 || 5
      featuredInstructor = {
        name: instructorObj.full_name,
        phone: instructorObj.whatsapp_phone || '51999999999',
        experienceYears: mockYears,
        bio: `¡Hola! Soy ${instructorObj.full_name}, un apasionado del fitness con un enfoque en entrenamiento funcional y rutinas de alta intensidad. Mi objetivo es ayudarte a alcanzar tu mejor versión en cada sesión, entregándote toda la energía y motivación que necesitas para romper tus límites.`,
      }
    }
  }

  return (
    <div className="w-full max-w-7xl mx-auto px-5 md:px-8 py-12 md:py-16 space-y-16">
      <div className="space-y-4 text-center md:text-left">
        <h1 className="text-3xl md:text-5xl font-bold text-foreground">Próximas Clases</h1>
        <p className="text-[15px] md:text-lg text-foreground/80">Encuentra tu horario ideal y asegura tu lugar en nuestras sesiones guiadas.</p>
      </div>

      <ClassFilters instructors={instructorsList} />

      {mappedSessions.length === 0 ? (
        <div className="text-center py-16 md:py-20 px-6 bg-foreground/5 rounded-3xl border border-foreground/10">
          <p className="text-[15px] md:text-lg text-foreground/80 font-medium leading-relaxed">No hay clases programadas por el momento. ¡Vuelve pronto!</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5 md:gap-8">
          {mappedSessions.map(session => (
            <ClassCard key={session.id} {...session} referrer="clases" />
          ))}
        </div>
      )}
    </div>
  )
}

import { createClient } from '@/lib/supabase/server'
import { InstructorCard } from '@/features/instructors/components/InstructorCard'

export default async function InstructorsPage() {
  const supabase = await createClient()

  const { data: instructorsData } = await supabase
    .from('instructors')
    .select('id, full_name, years_experience, bio, whatsapp_phone')
    .order('created_at', { ascending: true })

  return (
    <div className="w-full max-w-7xl mx-auto px-5 md:px-8 py-12 md:py-16 space-y-16">
      <div className="space-y-4 text-center md:text-left">
        <h1 className="text-3xl md:text-5xl font-bold text-foreground">Nuestros Instructores</h1>
        <p className="text-[15px] md:text-lg text-foreground/80">Conoce al equipo de profesionales que te guiará en cada paso de tu transformación.</p>
      </div>

      {!instructorsData || instructorsData.length === 0 ? (
        <div className="text-center py-20 bg-foreground/5 rounded-3xl border border-foreground/10">
          <p className="text-lg text-foreground/80 font-medium">Aún no hay instructores registrados.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 md:gap-8">
          {instructorsData.map((instructor: any) => (
            <InstructorCard 
              key={instructor.id}
              name={instructor.full_name}
              experienceYears={instructor.years_experience}
              bio={instructor.bio}
              whatsapp={instructor.whatsapp_phone}
            />
          ))}
        </div>
      )}
    </div>
  )
}

import { createAdminClient } from '@/lib/supabase/server'
import { notFound } from 'next/navigation'
import { BookingStepper } from '@/features/booking/components/BookingStepper'
import { TopBar } from '@/features/shared/components/TopBar'
import { SpaceSelectionFlow } from '@/features/booking/components/SpaceSelectionFlow'

function formatSessionDate(isoString: string) {
  const date = new Date(isoString)
  return new Intl.DateTimeFormat('es-PE', { weekday: 'long', day: 'numeric', month: 'long' }).format(date)
}

function formatSessionTime(isoString: string) {
  const date = new Date(isoString)
  return new Intl.DateTimeFormat('es-PE', { hour: '2-digit', minute: '2-digit', hour12: true }).format(date)
}

export default async function SpaceSelectionPage({ params }: { params: Promise<{ id: string }> }) {
  const resolvedParams = await params
  const supabase = createAdminClient()

  const { data, error } = await supabase
    .from('sessions')
    .select(`
      id,
      session_date,
      start_time,
      capacity,
      capacity,
      session_spots ( id, spot_number, status, reservation_spots( reservation_id, reservations( estado_pago, expira_en ) ) )
    `)
    .eq('id', resolvedParams.id)
    .single()

  const session = data as any

  if (error || !session) {
    notFound()
  }

  const dateStr = formatSessionDate(`${session.session_date}T${session.start_time}`)
  const timeStr = formatSessionTime(`${session.session_date}T${session.start_time}`)
  
  let spots = session.session_spots || []
  
  // Passive release of expired spots
  spots = spots.map((spot: any) => {
    if (spot.status !== 'available') {
      const resSpots = spot.reservation_spots;
      const resSpotsArray = Array.isArray(resSpots) ? resSpots : (resSpots ? [resSpots] : []);
      const hasExpired = resSpotsArray.some((rs: any) => {
        const res = rs.reservations;
        return res && res.estado_pago === 'pendiente' && res.expira_en && new Date(res.expira_en) < new Date();
      });
      if (hasExpired) {
        return { ...spot, status: 'available' };
      }
    }
    return spot;
  });

  return (
    <div className="min-h-screen bg-background flex flex-col relative overflow-hidden">
      <TopBar title="Selecciona tu Espacio" backHref={`/reserva/${resolvedParams.id}`} />

      <BookingStepper currentStep={2} />

      <div className="text-center mt-4 mb-4 px-5">
         <p className="text-foreground/80 text-sm font-medium capitalize mb-1">{dateStr} - {timeStr}</p>
         <p className="text-foreground/70 text-xs">Toca el número del espacio en el mapa para reservarlo.</p>
      </div>

      <SpaceSelectionFlow 
        sessionId={session.id} 
        capacity={session.capacity} 
        spots={spots} 
      />
    </div>
  )
}

import { NextRequest, NextResponse } from 'next/server';
import { MercadoPagoConfig, Preference } from 'mercadopago';
import { createAdminClient } from '@/lib/supabase/server';

export async function POST(req: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  try {
    const resolvedParams = await params;
    const reservationId = resolvedParams.id;

    if (!reservationId) {
      return NextResponse.json({ error: 'Missing reservation ID' }, { status: 400 });
    }

    const supabase = createAdminClient();

    // 1. Fetch reservation details
    const { data: reservation, error } = await supabase
      .from('reservations')
      .select(`
        id, 
        total_amount, 
        estado_pago,
        session_id,
        sessions (
          theme
        )
      `)
      .eq('id', reservationId)
      .single();

    if (error || !reservation) {
      return NextResponse.json({ error: 'Reservation not found' }, { status: 404 });
    }

    if (reservation.estado_pago === 'aprobado') {
      return NextResponse.json({ error: 'Reservation already paid' }, { status: 400 });
    }

    // 2. Initialize Mercado Pago
    const client = new MercadoPagoConfig({ 
      accessToken: process.env.MP_ACCESS_TOKEN || '', 
      options: { timeout: 5000 } 
    });
    
    const preference = new Preference(client);

    const baseUrl = process.env.VERCEL_URL
      ? `https://${process.env.VERCEL_URL}`
      : 'http://localhost:3000';
      
    const notificationUrl = `${baseUrl}/api/webhooks/mercadopago`;

    const theme = (reservation.sessions as any)?.theme || 'Clase de Entrenamiento';

    // 3. Create Preference
    const response = await preference.create({
      body: {
        items: [
          {
            id: reservation.id,
            title: `Reserva - ${theme}`,
            quantity: 1,
            unit_price: Number(reservation.total_amount),
            currency_id: 'PEN'
          }
        ],
        external_reference: reservation.id,
        back_urls: {
          success: `${baseUrl}/pago/exito`,
          pending: `${baseUrl}/pago/pendiente`,
          failure: `${baseUrl}/pago/fallo`
        },
        auto_return: 'approved',
        notification_url: notificationUrl
      }
    });

    if (!response.init_point) {
      throw new Error('No init_point received from Mercado Pago');
    }

    // 4. Update reservation with preference ID
    await supabase
      .from('reservations')
      .update({ mp_preference_id: response.id })
      .eq('id', reservation.id);

    return NextResponse.json({ init_point: response.init_point });

  } catch (error: any) {
    console.error('Mercado Pago Error:', error);
    return NextResponse.json({ error: error.message || 'Internal Server Error' }, { status: 500 });
  }
}

"use client"

import { useState } from 'react'
import Link from 'next/link'
import { usePathname, useRouter } from 'next/navigation'
import { Menu, X, LogIn, Calendar, Users, Home, LayoutDashboard, LogOut, PlusCircle, Activity, Undo2 } from 'lucide-react'
import { createClient } from '@/lib/supabase/client'
import { ThemeToggle } from '@/components/ThemeToggle'

export function Navbar({ user }: { user?: any }) {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false)
  const [isDropdownOpen, setIsDropdownOpen] = useState(false)
  const pathname = usePathname()

  const router = useRouter()
  const supabase = createClient()

  const publicNavLinks = [
    { href: '/', label: 'Inicio', icon: Home },
    { href: '/clases', label: 'Clases', icon: Calendar },
    { href: '/instructores', label: 'Nuestro Equipo', icon: Users },
