'use client'

import { useRouter, useSearchParams, usePathname } from 'next/navigation'
import { useCallback, useState, useRef, useEffect } from 'react'
import DatePicker from 'react-datepicker'
import "react-datepicker/dist/react-datepicker.css"
import { Calendar as CalendarIcon, ChevronDown, User } from 'lucide-react'

export function ClassFilters({ instructors }: { instructors: { id: string, name: string }[] }) {
  const router = useRouter()
  const pathname = usePathname()
  const searchParams = useSearchParams()

  const [instructorId, setInstructorId] = useState(searchParams.get('instructor') || '')
  
  // Date picker usa el objeto Date nativo.
  // parsear la fecha "YYYY-MM-DD" si existe en la URL cuidando el timezone.
  const queryDate = searchParams.get('date')
  const [date, setDate] = useState<Date | null>(queryDate ? new Date(queryDate + 'T00:00:00') : null)
  
  const [isDropdownOpen, setIsDropdownOpen] = useState(false)
  const dropdownRef = useRef<HTMLDivElement>(null)

  // Cerrar el dropdown al hacer click fuera
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsDropdownOpen(false)
      }
    }
    document.addEventListener("mousedown", handleClickOutside)
    return () => document.removeEventListener("mousedown", handleClickOutside)
  }, [])

  const handleApply = () => {
    let params = new URLSearchParams(searchParams.toString())
    if (instructorId) params.set('instructor', instructorId)
    else params.delete('instructor')
    
    if (date) {
      const year = date.getFullYear()
      const month = String(date.getMonth() + 1).padStart(2, '0')
      const day = String(date.getDate()).padStart(2, '0')
      params.set('date', `${year}-${month}-${day}`)
    } else {
      params.delete('date')
    }

    router.push(`${pathname}?${params.toString()}`)
  }

  const handleClear = () => {
    setInstructorId('')
    setDate(null)
    router.push(pathname)
  }

  const selectedInstructorName = instructors.find(i => i.id === instructorId)?.name || 'Todos los instructores'

  return (
    <div className="bg-container border border-foreground/10 rounded-[20px] p-5 flex flex-col md:flex-row gap-4 mb-8 shadow-lg">
      
      {/* Dropdown de Instructores Personalizado */}
      <div className="flex-1" ref={dropdownRef}>
        <label className="text-[11px] text-foreground/70 uppercase tracking-wider font-bold mb-2 block ml-1">Filtrar por Instructor</label>
        <div className="relative">
          <button
            type="button"
            onClick={() => setIsDropdownOpen(!isDropdownOpen)}
            className="w-full bg-background border border-foreground/10 hover:border-[#D6007A]/50 rounded-xl p-3.5 text-[13px] text-foreground flex items-center justify-between transition-colors shadow-inner"
          >
            <div className="flex items-center gap-2">
              <User className="w-4 h-4 text-[#D6007A]" />
              <span className="font-medium truncate">{selectedInstructorName}</span>
            </div>
            <ChevronDown className={`w-4 h-4 text-foreground/70 transition-transform ${isDropdownOpen ? 'rotate-180' : ''}`} />
          </button>

          {isDropdownOpen && (
            <div className="absolute z-50 w-full mt-2 bg-background border border-foreground/10 rounded-xl shadow-2xl overflow-hidden py-1 animate-in fade-in slide-in-from-top-2">
              <button
                type="button"
                className={`w-full text-left px-4 py-3 text-[13px] font-medium transition-colors hover:bg-foreground/5 ${instructorId === '' ? 'text-[#D6007A] bg-[#D6007A]/10' : 'text-foreground'}`}
                onClick={() => {
                  setInstructorId('')
                  setIsDropdownOpen(false)
                }}
              >
                Todos los instructores
              </button>
              {instructors.map(inst => (
                <button
                  key={inst.id}
                  type="button"
                  className={`w-full text-left px-4 py-3 text-[13px] font-medium transition-colors hover:bg-foreground/5 ${instructorId === inst.id ? 'text-[#D6007A] bg-[#D6007A]/10' : 'text-foreground'}`}
                  onClick={() => {
                    setInstructorId(inst.id)
                    setIsDropdownOpen(false)
                  }}
                >
                  {inst.name}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Selector de Fecha (react-datepicker) */}
      <div className="flex-1">
        <label className="text-[11px] text-foreground/70 uppercase tracking-wider font-bold mb-2 block ml-1">Filtrar por Fecha</label>
        <div className="relative flex items-center">
          <div className="absolute left-0 pl-3.5 flex items-center pointer-events-none z-10">
            <CalendarIcon className="w-4 h-4 text-[#D6007A]" />
          </div>
          <style dangerouslySetInnerHTML={{__html: `
            .custom-datepicker .react-datepicker__input-container input {
              width: 100%;
              background-color: rgba(214, 0, 122, 0.05);
              border: 1px solid rgba(214, 0, 122, 0.2);
              border-radius: 0.75rem;
              padding: 0.875rem 1rem 0.875rem 2.5rem;
              font-size: 13px;
              color: var(--foreground);
              font-weight: 500;
              transition: all 0.2s;
              box-shadow: inset 0 2px 4px 0 rgba(0, 0, 0, 0.05);
            }
            .custom-datepicker .react-datepicker__input-container input:hover {
              border-color: rgba(214, 0, 122, 0.5);
              background-color: rgba(214, 0, 122, 0.08);
            }
            .custom-datepicker .react-datepicker__input-container input:focus {
              outline: none;
              border-color: rgba(214, 0, 122, 0.8);
              box-shadow: 0 0 0 3px rgba(214, 0, 122, 0.15);
            }
            
            /* DatePicker Popup Theme Overrides */
            .react-datepicker-popper[data-placement^="bottom"] .react-datepicker__triangle::before,
            .react-datepicker-popper[data-placement^="bottom"] .react-datepicker__triangle::after,
            .react-datepicker-popper[data-placement^="top"] .react-datepicker__triangle::before,
            .react-datepicker-popper[data-placement^="top"] .react-datepicker__triangle::after {
              border-bottom-color: var(--background) !important;
              border-top-color: var(--background) !important;
            }
            
            .react-datepicker {
              background-color: var(--background) !important;
              border: 1px solid color-mix(in srgb, var(--foreground) 10%, transparent) !important;
              border-radius: 1rem !important;
              font-family: inherit !important;
              box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5) !important;
            }
            .react-datepicker__header {
              background-color: var(--container) !important;
              border-bottom: 1px solid color-mix(in srgb, var(--foreground) 5%, transparent) !important;
              border-top-left-radius: 1rem !important;
              border-top-right-radius: 1rem !important;
            }
            .react-datepicker__current-month, 
            .react-datepicker-time__header, 
            .react-datepicker-year-header {
              color: var(--foreground) !important;
            }
            .react-datepicker__day-name, 
            .react-datepicker__day, 
            .react-datepicker__time-name {
              color: var(--foreground) !important;
            }
            .react-datepicker__day:hover,
            .react-datepicker__month-text:hover,
            .react-datepicker__quarter-text:hover,
            .react-datepicker__year-text:hover {
              background-color: rgba(214, 0, 122, 0.3) !important;
              border-radius: 0.5rem !important;
              color: var(--foreground) !important;
            }
            .react-datepicker__day--selected, 
            .react-datepicker__day--keyboard-selected {
              background-color: #D6007A !important;
              color: white !important;
              border-radius: 0.5rem !important;
            }
            .react-datepicker__day--outside-month {
              color: var(--foreground) !important;
              opacity: 0.3 !important;
            }
          `}} />
          <DatePicker
            selected={date}
            onChange={(d: Date | null) => setDate(d)}
            dateFormat="dd/MM/yyyy"
            placeholderText="Selecciona una fecha"
            className="w-full"
            wrapperClassName="w-full custom-datepicker"
            isClearable
          />
        </div>
      </div>

      <div className="flex gap-3 items-end md:w-auto w-full pt-2 md:pt-0">
        <button 
          onClick={handleClear}
          className="flex-1 md:flex-none h-[46px] flex items-center justify-center px-4 text-[13px] font-semibold text-foreground/80 bg-foreground/5 rounded-xl hover:bg-foreground/10 transition-colors whitespace-nowrap"
        >
          Limpiar
        </button>
        <button 
          onClick={handleApply}
          className="flex-1 md:flex-none h-[46px] flex items-center justify-center px-4 bg-gradient-to-r from-[#D6007A] to-[#9B00E8] rounded-xl text-[13px] font-bold text-white shadow-lg hover:opacity-90 transition-opacity whitespace-nowrap"
        >
          Aplicar Filtros
        </button>
      </div>
    </div>
  )
}

"use server"

import { createClient } from '@/lib/supabase/server'
import { revalidatePath } from 'next/cache'

export async function completeRefund(refundId: string) {
  const supabase = await createClient()

  // Verify auth
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) throw new Error('Unauthorized')

  // We have RLS policies on refunds ensuring instructor can only update their own refunds
  const { error } = await supabase
    .from('refunds' as any)
    .update({ status: 'completed', completed_at: new Date().toISOString() })
    .eq('id', refundId)

  if (error) {
    console.error("Complete refund error:", error)
    throw new Error('Error al actualizar la devolución')
  }

  revalidatePath('/panel/devoluciones')
}

'use server'

import { createClient } from '@/lib/supabase/server'
import { revalidatePath } from 'next/cache'
import { redirect } from 'next/navigation'

export async function createSession(formData: FormData) {
  const supabase = await createClient()
  const { data: { user } } = await supabase.auth.getUser()
  
  if (!user) {
    throw new Error('No autorizado')
  }

  const session_date = formData.get('session_date') as string
  const start_time = formData.get('start_time') as string
  const special_guest = formData.get('special_guest') as string
  const theme = formData.get('theme') as string
  const class_type = formData.get('class_type') as string
  const price = parseFloat(formData.get('price') as string)
  const whatsapp_contact = formData.get('whatsapp_contact') as string
  const capacity = parseInt(formData.get('capacity') as string)

  if (!session_date || !start_time || !class_type || isNaN(price) || !whatsapp_contact || isNaN(capacity)) {
    throw new Error('Campos obligatorios faltantes')
  }

  const { data: newSession, error: sessionError } = await supabase
    .from('sessions')
    .insert({
      instructor_id: user.id,
      session_date,
      start_time,
      special_guest: special_guest || null,
      theme: theme || null,
      class_type,
      price,
      whatsapp_contact,
      capacity,
      status: 'published'
    })
    .select('id')
    .single()

  if (sessionError) {
    console.error('Error creating session:', sessionError)
    throw new Error('Error al crear la sesión en la base de datos')
  }

  // Create session spots
  const spots = Array.from({ length: capacity }, (_, i) => ({
    session_id: newSession.id,
    spot_number: i + 1,
    status: 'available'
  }))

  const { error: spotsError } = await supabase
    .from('session_spots')
    .insert(spots as any) // cast to any to avoid ts errors

  if (spotsError) {
    console.error('Error creating spots:', spotsError)
    throw new Error('Error al generar los espacios de la sesión')
  }

  revalidatePath('/panel')
  revalidatePath('/clases')
  redirect('/panel')
}

'use server'

import { createClient } from '@/lib/supabase/server'
import { revalidatePath } from 'next/cache'

export async function manualCheckIn(sessionId: string, spotNumber: number, formData: FormData) {
  const supabase = await createClient()

  // Verify auth
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) throw new Error('Unauthorized')

  const clientName = formData.get('client_name') as string
  const clientPhone = formData.get('client_phone') as string

  if (!clientName || !clientPhone) {
    throw new Error('Faltan datos del cliente')
  }

  // 1. Ensure the spot exists
  let { data: spot, error: spotError } = await supabase
    .from('session_spots')
    .select('id, status')
    .eq('session_id', sessionId)
    .eq('spot_number', spotNumber)
    .single()

  if (spotError && spotError.code !== 'PGRST116') {
    throw new Error('Error al obtener el espacio')
  }

  if (spot && spot.status !== 'available') {
    throw new Error('El espacio ya no está disponible')
  }

  let spotId = spot?.id

  if (!spot) {
    const { data: newSpot, error: insertError } = await supabase
      .from('session_spots')
      .insert({
        session_id: sessionId,
        spot_number: spotNumber,
        status: 'available'
      })
      .select('id')
      .single()

    if (insertError || !newSpot) {
      throw new Error('Error al crear el espacio')
    }
    spotId = newSpot.id
  }

  // 2. Call create_reservation RPC
  const { data: reservationId, error: reserveError } = await supabase.rpc('create_reservation', {
    p_session_id: sessionId,
    p_client_name: clientName,
    p_client_phone: clientPhone,
    p_spot_ids: [spotId as string]
  })

  if (reserveError || !reservationId) {
    throw new Error('Error al crear la reserva: ' + reserveError?.message)
  }

  // 3. Update reservation status to 'confirmed' and estado_pago to 'aprobado'
  const { error: updateError } = await supabase
    .from('reservations')
    .update({ 
      status: 'confirmed',
      estado_pago: 'aprobado'
    })
    .eq('id', reservationId)

  if (updateError) {
    throw new Error('Error al confirmar la reserva')
  }

  // 4. Update the spot status to 'present'
  const { error: finalSpotError } = await supabase
    .from('session_spots')
    .update({ status: 'present' })
    .eq('id', spotId as string)

  if (finalSpotError) {
    throw new Error('Error al registrar la asistencia')
  }

  revalidatePath(`/panel/asistencia/${sessionId}`)
}

'use client'

import { useState, useTransition } from 'react'
import { AlertCircle, Loader2, X } from 'lucide-react'
import { cancelSession, getCancelImpact } from '../actions/cancelSession'

interface CancelSessionButtonProps {
  sessionId: string
  variant?: 'full' | 'menu-item'
}

export function CancelSessionButton({ sessionId, variant = 'full' }: CancelSessionButtonProps) {
  const [isOpen, setIsOpen] = useState(false)
  const [isPending, startTransition] = useTransition()
  const [isFetching, setIsFetching] = useState(false)
  const [impact, setImpact] = useState<{ impactedReservations: number, totalRefundAmount: number } | null>(null)

  const handleOpenClick = async () => {
    setIsFetching(true)
    try {
      const data = await getCancelImpact(sessionId)
      setImpact(data)
      setIsOpen(true)
    } catch (e: any) {
      alert(e.message || 'Error al calcular impacto')
    } finally {
      setIsFetching(false)
    }
  }

  const handleConfirm = () => {
    startTransition(async () => {
      try {
        await cancelSession(sessionId)
      } catch (e: any) {
        alert(e.message || 'Ocurrió un error al cancelar la clase')
      }
    })
  }

  return (
    <>
      {variant === 'full' ? (
        <button 
          onClick={handleOpenClick}
          disabled={isFetching}
          className="w-full bg-container text-pink-500 font-semibold rounded-xl py-3.5 border border-pink-500/20 transition-colors hover:bg-pink-500/10 disabled:opacity-50 flex items-center justify-center gap-2"
        >
          {isFetching && <Loader2 className="w-4 h-4 animate-spin" />}
          Cancelar Clase
        </button>
      ) : (
        <button 
          onClick={handleOpenClick}
          disabled={isFetching}
          className="w-full text-left px-4 py-3 text-red-500 hover:bg-red-500/10 transition-colors text-sm font-medium flex items-center justify-between"
        >
          Cancelar Clase
          {isFetching && <Loader2 className="w-4 h-4 animate-spin" />}
        </button>
      )}

      {isOpen && impact && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-5 animate-in fade-in zoom-in duration-200">
          <div className="bg-container border border-foreground/10 rounded-3xl w-full max-w-sm overflow-hidden shadow-2xl relative">
            <div className="p-6 pb-0 flex justify-between items-start">
              <div className="w-12 h-12 rounded-full bg-red-500/10 flex items-center justify-center">
                <AlertCircle className="w-6 h-6 text-red-500" />
              </div>
              <button 
                onClick={() => setIsOpen(false)}
                className="text-foreground/50 hover:text-foreground transition-colors"
                disabled={isPending}
              >
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="p-6 space-y-4">
              <div>
                <h3 className="text-xl font-bold text-foreground mb-2">¿Cancelar Clase?</h3>
                <p className="text-foreground/70 text-sm">
                  Esta acción cancelará la clase y deberás gestionar el reembolso de los alumnos afectados. ¿Deseas continuar?
                </p>
              </div>

              <div className="bg-red-500/5 border border-red-500/10 rounded-2xl p-4 space-y-3">
                <div className="flex justify-between items-center text-sm">
                  <span className="text-foreground/70">Reservas afectadas:</span>
                  <span className="font-bold text-foreground">{impact.impactedReservations}</span>
                </div>
                <div className="flex justify-between items-center text-sm">
                  <span className="text-foreground/70">Monto a reembolsar:</span>
                  <span className="font-bold text-red-500">S/ {impact.totalRefundAmount.toFixed(2)}</span>
                </div>
              </div>

              <div className="pt-2 space-y-3">
                <button 
                  onClick={handleConfirm}
                  disabled={isPending}
                  className="w-full bg-red-500 hover:bg-red-600 text-white font-bold rounded-xl py-3.5 flex items-center justify-center gap-2 transition-colors disabled:opacity-50 disabled:pointer-events-none"
                >
                  {isPending ? (
                    <>
                      <Loader2 className="w-5 h-5 animate-spin" />
                      Cancelando...
                    </>
                  ) : (
                    'Sí, cancelar clase'
                  )}
                </button>
                <button 
                  onClick={() => setIsOpen(false)}
                  disabled={isPending}
                  className="w-full bg-transparent text-foreground/70 font-semibold rounded-xl py-3.5 hover:bg-foreground/5 transition-colors"
                >
                  Mantener clase
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  )
}

'use client'

import { useTransition } from 'react'
import { X, Loader2, Check } from 'lucide-react'
import { toggleAttendance } from '../actions/toggleAttendance'

interface ConfirmCheckInModalProps {
  sessionId: string
  spotNumber: number
  clientName: string
  estadoPago: string
  status: 'reserved' | 'present'
  isOpen: boolean
  onClose: () => void
}

export function ConfirmCheckInModal({ sessionId, spotNumber, clientName, estadoPago, status, isOpen, onClose }: ConfirmCheckInModalProps) {
  const [isPending, startTransition] = useTransition()

  if (!isOpen) return null

  const isPresent = status === 'present'

  const handleConfirm = () => {
    startTransition(async () => {
      try {
        await toggleAttendance(sessionId, spotNumber)
        onClose()
      } catch (e) {
        alert('Ocurrió un error al actualizar la asistencia')
      }
    })
  }

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-5">
      <div className="bg-container border border-foreground/10 rounded-3xl w-full max-w-sm overflow-hidden shadow-2xl relative animate-in fade-in zoom-in duration-200">
        <div className="bg-gradient-to-r from-pink-500 to-purple-600 p-6 text-white relative">
          <button 
            onClick={onClose}
            className="absolute top-4 right-4 text-white/80 hover:text-white transition-colors"
          >
            <X className="w-6 h-6" />
          </button>
          
          <h2 className="text-xl font-bold">Espacio #{spotNumber} - {clientName || 'Cliente'}</h2>
        </div>

        <div className="p-6 space-y-6 flex flex-col items-center">
          <div className="text-center space-y-2 w-full">
            <div className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-sm font-semibold ${estadoPago === 'aprobado' ? 'bg-[#00E676]/10 text-[#00E676]' : 'bg-orange-500/10 text-orange-500'}`}>
              {estadoPago === 'aprobado' ? (
                <>Pago verificado <Check className="w-4 h-4" /></>
              ) : (
                `Pago ${estadoPago}`
              )}
            </div>
            
            <p className="text-foreground/70 font-medium pt-2">
              {isPresent ? 'Asistencia Confirmada' : 'Alumno aún no ha llegado'}
            </p>
          </div>

          <div className="w-full space-y-3">
            <button 
              onClick={handleConfirm}
              disabled={isPending}
              className={`w-full font-bold rounded-xl py-3.5 flex items-center justify-center gap-2 transition-all disabled:opacity-50 disabled:pointer-events-none ${isPresent ? 'bg-foreground/10 text-foreground hover:bg-foreground/20' : 'bg-gradient-to-r from-pink-500 to-purple-600 text-white hover:brightness-110'}`}
            >
              {isPending ? (
                <>
                  <Loader2 className="w-5 h-5 animate-spin" />
                  Actualizando...
                </>
              ) : (
                isPresent ? 'Deshacer Check-in' : 'Confirmar Check-in Manual'
              )}
            </button>
            <button 
              onClick={onClose}
              disabled={isPending}
              className="w-full bg-transparent text-foreground/70 font-semibold rounded-xl py-3.5 hover:bg-foreground/5 transition-colors"
            >
              Cerrar
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

"use client"

import { useTransition, useState } from 'react'
import { cn } from '@/lib/utils'
import { User, CheckCircle2, Users, MinusCircle } from 'lucide-react'
import { toggleAttendance } from '../actions/toggleAttendance'
import { ManualCheckInModal } from './ManualCheckInModal'
import { ConfirmCheckInModal } from './ConfirmCheckInModal'

function getOccupationTextColor(percentage: number) {
  if (percentage < 50) return 'text-[#00E676]'
  if (percentage < 90) return 'text-orange-500'
  return 'text-pink-500'
}

function getOccupationBgColor(percentage: number) {
  if (percentage < 50) return 'bg-[#00E676]/20'
  if (percentage < 90) return 'bg-orange-500/20'
  return 'bg-pink-500/20'
}

export interface SpotData {
  spot_number: number
  status: 'available' | 'reserved' | 'present'
  reservation_spots?: {
    reservations?: {
      client_name: string
      estado_pago: string | null
      total_amount?: number
    }
  } | null
}

interface LiveAttendanceProps {
  sessionId: string
  capacity: number
  spots: SpotData[]
}

export function LiveAttendance({ sessionId, capacity, spots }: LiveAttendanceProps) {
  const [isPending, startTransition] = useTransition()
  const [selectedFreeSpot, setSelectedFreeSpot] = useState<number | null>(null)
  const [selectedReservedSpot, setSelectedReservedSpot] = useState<number | null>(null)

  const allSpots = Array.from({ length: capacity }, (_, i) => {
    const spotNumber = i + 1
    const dbSpot = spots.find(s => s.spot_number === spotNumber)
    return {
      spot_number: spotNumber,
      status: dbSpot ? dbSpot.status : 'available',
      reservation_spots: dbSpot?.reservation_spots
    }
  })

  const countPresent = allSpots.filter(s => s.status === 'present').length
  const countReserved = allSpots.filter(s => s.status === 'reserved').length
  const countAvailable = allSpots.filter(s => s.status === 'available').length

  const totalOccupied = countPresent + countReserved
  const occupationPercentage = capacity > 0 ? (totalOccupied / capacity) * 100 : 0
  const occupationTextColor = getOccupationTextColor(occupationPercentage)
  const occupationBgColor = getOccupationBgColor(occupationPercentage)

  const handleSpotClick = (spotNumber: number, status: string) => {
    if (status === 'available') {
      setSelectedFreeSpot(spotNumber)
    } else {
      setSelectedReservedSpot(spotNumber)
    }
  }

  return (
    <div className="w-full flex flex-col gap-6">
      {/* Stats Cards */}
      <div className="grid grid-cols-3 gap-3">
        <div className="bg-container border border-foreground/5 rounded-2xl p-4 flex flex-col items-center justify-center gap-2">
          <div className="w-10 h-10 rounded-full bg-[#00E676]/20 flex items-center justify-center">
            <CheckCircle2 className="w-5 h-5 text-[#00E676]" />
          </div>
          <span className="text-xl font-bold text-foreground">{countPresent}</span>
          <span className="text-[10px] text-foreground/70 uppercase tracking-wider font-semibold">Presentes</span>
        </div>
        
        <div className="bg-container border border-foreground/5 rounded-2xl p-4 flex flex-col items-center justify-center gap-2">
          <div className={`w-10 h-10 rounded-full ${occupationBgColor} flex items-center justify-center`}>
            <Users className={`w-5 h-5 ${occupationTextColor}`} />
          </div>
          <span className={`text-xl font-bold ${occupationTextColor}`}>{totalOccupied}/{capacity}</span>
          <span className="text-[10px] text-foreground/70 uppercase tracking-wider font-semibold">Reservados</span>
        </div>

        <div className="bg-container border border-foreground/5 rounded-2xl p-4 flex flex-col items-center justify-center gap-2">
          <div className="w-10 h-10 rounded-full bg-foreground/10 flex items-center justify-center">
            <MinusCircle className="w-5 h-5 text-foreground/50" />
          </div>
          <span className="text-xl font-bold text-foreground">{countAvailable}</span>
          <span className="text-[10px] text-foreground/70 uppercase tracking-wider font-semibold">Libres</span>
        </div>
      </div>

      {/* Grid Container */}
      <div className="bg-container border border-foreground/5 rounded-3xl p-5 shadow-lg relative">
        {isPending && (
          <div className="absolute inset-0 bg-background/50 rounded-3xl z-10 flex items-center justify-center">
             <div className="w-6 h-6 border-2 border-pink-500 border-t-transparent rounded-full animate-spin"></div>
          </div>
        )}
        
        <div className="flex justify-center mb-6">
          <div className="w-full max-w-[280px] bg-gradient-to-r from-pink-500 to-purple-600 rounded-xl py-3 px-4 flex items-center justify-center gap-2 shadow-lg shadow-pink-500/20">
            <User className="w-5 h-5 text-white" />
            <span className="text-white font-semibold tracking-wide text-sm">INSTRUCTOR / ESPEJO</span>
          </div>
        </div>

        <div className="grid grid-cols-5 gap-3 max-w-[280px] mx-auto mb-8">
          {allSpots.map(spot => {
            const isAvailable = spot.status === 'available'
            const isReserved = spot.status === 'reserved'
            const isPresent = spot.status === 'present'

            return (
              <button
                key={spot.spot_number}
                onClick={() => handleSpotClick(spot.spot_number, spot.status)}
                className={cn(
                  'w-full aspect-square rounded-lg flex items-center justify-center text-sm font-bold transition-all shadow-sm',
                  isAvailable && 'bg-background border border-foreground/10 text-foreground hover:bg-foreground/5',
                  isReserved && 'bg-pink-500 text-white hover:brightness-110',
                  isPresent && 'bg-[#00E676] text-black hover:brightness-110'
                )}
              >
                {spot.spot_number}
              </button>
            )
          })}
        </div>

        {/* Legend */}
        <div className="flex flex-col gap-3 max-w-[280px] mx-auto text-xs font-medium text-foreground/70">
          <div className="flex items-center gap-3">
            <div className="w-4 h-4 rounded bg-background border border-foreground/10"></div>
            <span>Espacio libre/disponible</span>
          </div>
          <div className="flex items-center gap-3">
            <div className="w-4 h-4 rounded bg-pink-500"></div>
            <span>Reservado (pago verificado)</span>
          </div>
          <div className="flex items-center gap-3">
            <div className="w-4 h-4 rounded bg-[#00E676]"></div>
            <span>Alumno presente (check-in)</span>
          </div>
        </div>
      </div>

      <ManualCheckInModal 
        sessionId={sessionId}
        spotNumber={selectedFreeSpot || 0}
        isOpen={selectedFreeSpot !== null}
        onClose={() => setSelectedFreeSpot(null)}
      />

      {selectedReservedSpot !== null && (() => {
        const spotInfo = allSpots.find(s => s.spot_number === selectedReservedSpot)
        const resData = spotInfo?.reservation_spots?.reservations
        const clientName = resData?.client_name || 'Cliente'
        const estadoPago = resData?.estado_pago || 'pendiente'
        
        return (
          <ConfirmCheckInModal
            sessionId={sessionId}
            spotNumber={selectedReservedSpot}
            clientName={clientName}
            estadoPago={estadoPago}
            status={spotInfo?.status as 'reserved' | 'present'}
            isOpen={true}
            onClose={() => setSelectedReservedSpot(null)}
          />
        )
      })()}
    </div>
  )
}

'use client'

import { useState, useTransition } from 'react'
import { User, CheckCircle2, X, Loader2 } from 'lucide-react'
import { manualCheckIn } from '../actions/manualCheckIn'
import { Input } from '@/features/shared/components/Input'

interface ManualCheckInModalProps {
  sessionId: string
  spotNumber: number
  isOpen: boolean
  onClose: () => void
}

export function ManualCheckInModal({ sessionId, spotNumber, isOpen, onClose }: ManualCheckInModalProps) {
  const [isPending, startTransition] = useTransition()
  const [clientName, setClientName] = useState('')
  const [clientPhone, setClientPhone] = useState('')
  const [phoneError, setPhoneError] = useState('')

  if (!isOpen) return null

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    // Solo permitir letras (incluyendo tildes y eñes) y espacios
    const value = e.target.value
    const filtered = value.replace(/[^a-zA-ZáéíóúÁÉÍÓÚñÑüÜ ]/g, '')
    setClientName(filtered)
  }

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value
    // Solo permitir números
    const filtered = value.replace(/\D/g, '')
    const truncated = filtered.slice(0, 9)
    setClientPhone(truncated)

    if (truncated.length > 0 && !/^9\d{8}$/.test(truncated)) {
      setPhoneError('El celular debe tener 9 dígitos y empezar con 9.')
    } else {
      setPhoneError('')
    }
  }

  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault()
    
    if (!/^9\d{8}$/.test(clientPhone)) {
      setPhoneError('El celular debe tener 9 dígitos y empezar con 9.')
      return
    }

    const formData = new FormData(e.currentTarget)
    
    startTransition(async () => {
      try {
        await manualCheckIn(sessionId, spotNumber, formData)
        onClose()
      } catch (e) {
        alert('Ocurrió un error al registrar el check-in manual.')
      }
    })
  }

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-5">
      <div className="bg-container border border-foreground/10 rounded-3xl w-full max-w-sm overflow-hidden shadow-2xl relative animate-in fade-in zoom-in duration-200">
        <div className="bg-gradient-to-r from-pink-500 to-purple-600 p-5 text-white pr-12">
          <h2 className="text-xl font-bold flex items-center gap-2">
            <CheckCircle2 className="w-5 h-5" />
            Check-in Manual
          </h2>
          <p className="text-white/80 text-sm mt-1">Espacio #{spotNumber} - Pago Presencial</p>
          <button 
            onClick={onClose}
            className="absolute top-4 right-4 text-white/80 hover:text-white transition-colors"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div className="space-y-1">
            <label className="text-sm font-medium text-foreground/80">Nombre Completo</label>
            <Input 
              name="client_name" 
              placeholder="Ej. Juan Pérez" 
              required 
              autoFocus
              value={clientName}
              onChange={handleNameChange}
              className="bg-background border-foreground/10"
            />
          </div>
          
          <div className="space-y-1">
            <label className="text-sm font-medium text-foreground/80">Celular</label>
            <Input 
              name="client_phone" 
              placeholder="Ej. 999888777" 
              required 
              type="tel"
              value={clientPhone}
              onChange={handlePhoneChange}
              maxLength={9}
              className={`bg-background border-foreground/10 ${phoneError ? 'border-red-500/50 focus:border-red-500' : ''}`}
            />
            {phoneError && (
              <p className="text-red-500 text-xs mt-1 font-medium">{phoneError}</p>
            )}
          </div>

          <div className="bg-foreground/5 border border-state-yellow/30 p-3 rounded-xl text-xs text-foreground/80 leading-relaxed mt-2">
            <strong className="text-state-yellow">Nota:</strong> Esto creará la reserva automáticamente con pago en efectivo y registrará la asistencia del alumno en este espacio.
          </div>

          <button 
            type="submit"
            disabled={isPending || !clientName.trim() || !/^9\d{8}$/.test(clientPhone)}
            className="w-full bg-gradient-to-r from-pink-500 to-purple-600 text-white font-bold rounded-xl py-3.5 mt-4 flex items-center justify-center gap-2 hover:brightness-110 active:scale-95 transition-all disabled:opacity-50 disabled:pointer-events-none"
          >
            {isPending ? (
              <>
                <Loader2 className="w-5 h-5 animate-spin" />
                Registrando...
              </>
            ) : (
              'Confirmar Check-in'
            )}
          </button>
        </form>
      </div>
    </div>
  )
}

"use client"

import { useState, useTransition } from 'react'
import { CheckCircle2, Phone, Calendar, User as UserIcon } from 'lucide-react'
import { completeRefund } from '../actions/completeRefund'

export function RefundItem({ refund }: { refund: any }) {
  const [isPending, startTransition] = useTransition()
  const [isSuccess, setIsSuccess] = useState(false)

  const handleComplete = () => {
    startTransition(async () => {
      try {
        await completeRefund(refund.id)
        setIsSuccess(true)
      } catch (e) {
        alert('Error al procesar la devolución.')
      }
    })
  }

  const isCompleted = refund.status === 'completed' || isSuccess
  const reservation = refund.reservations
  const session = reservation?.sessions
  const dateStr = session ? new Date(`${session.session_date}T${session.start_time}`).toLocaleString('es-PE', {
    day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit', hour12: true
  }) : 'Fecha desconocida'

  return (
    <div className={`p-4 rounded-2xl border ${isCompleted ? 'border-[#00E676]/30 bg-[#00E676]/5' : 'border-orange-500/30 bg-orange-500/5'} transition-colors`}>
      <div className="flex justify-between items-start mb-3">
        <div>
          <h3 className="font-bold text-foreground capitalize flex items-center gap-2">
            <UserIcon className="w-4 h-4 text-foreground/50" />
            {reservation?.client_name || 'Usuario desconocido'}
          </h3>
          <p className="text-xs text-foreground/60 flex items-center gap-2 mt-1">
            <Phone className="w-3 h-3" />
            {reservation?.client_phone || 'Sin número'}
          </p>
        </div>
        <div className="text-right">
          <span className="font-bold text-lg text-foreground">S/ {Number(refund.amount).toFixed(2)}</span>
          <p className={`text-xs font-semibold uppercase tracking-wide ${isCompleted ? 'text-[#00E676]' : 'text-orange-500'}`}>
            {isCompleted ? 'Completada' : 'Pendiente'}
          </p>
        </div>
      </div>

      <div className="flex items-center gap-2 text-xs text-foreground/70 mb-4 bg-background/50 p-2 rounded-lg">
        <Calendar className="w-4 h-4 text-[#D6007A]" />
        <span>Clase: <strong className="font-medium">{session?.theme || 'Myku'}</strong> - {dateStr}</span>
      </div>

      {!isCompleted && (
        <button
          onClick={handleComplete}
          disabled={isPending}
          className="w-full bg-[#D6007A] text-white font-bold py-3 rounded-xl flex justify-center items-center gap-2 hover:bg-[#D6007A]/80 transition-colors disabled:opacity-50"
        >
          {isPending ? 'Procesando...' : (
            <>
              <CheckCircle2 className="w-5 h-5" />
              Marcar como devuelto
            </>
          )}
        </button>
      )}
    </div>
  )
}

import { createServerClient } from '@supabase/ssr'
import { NextResponse, type NextRequest } from 'next/server'

export async function updateSession(request: NextRequest) {
  let supabaseResponse = NextResponse.next({
    request,
  })

  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_PUBLISHABLE_KEY!,
    {
      cookies: {
        getAll() {
          return request.cookies.getAll()
        },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value }) => request.cookies.set(name, value))
          supabaseResponse = NextResponse.next({
            request,
          })
          cookiesToSet.forEach(({ name, value, options }) =>
            supabaseResponse.cookies.set(name, value, options)
          )
        },
      },
    }
  )

  // Opcionalmente podemos obtener el usuario actual
  // const { data: { user } } = await supabase.auth.getUser()

  // Proteger rutas del instructor
  /*
  if (
    !user &&
    request.nextUrl.pathname.startsWith('/panel')
  ) {
    const url = request.nextUrl.clone()
    url.pathname = '/login'
    return NextResponse.redirect(url)
  }
  */

  return supabaseResponse
}
